{
  "mode": "method",
  "tests": [
    {
      "name": "valid_submission_download",
      "input": {
        "member_id": "12345",
        "submission_id": "abcde12345"
      },
      "output": "download_not_allowed",
      "args": [],
      "kwargs": {},
      "notes": "Tests that a member cannot download their own submission."
    },
    {
      "name": "invalid_submission_id",
      "input": {
        "member_id": "12345",
        "submission_id": "invalid_id"
      },
      "output": "submission_not_found",
      "args": [],
      "kwargs": {},
      "notes": "Tests behavior when an invalid submission ID is provided."
    },
    {
      "name": "non_member_download_attempt",
      "input": {
        "member_id": "67890",
        "submission_id": "abcde12345"
      },
      "output": "access_denied",
      "args": [],
      "kwargs": {},
      "notes": "Tests that a non-member cannot download a submission."
    },
    {
      "name": "multiple_download_attempts",
      "input": [
        {
          "member_id": "12345",
          "submission_id": "abcde12345"
        },
        {
          "member_id": "12345",
          "submission_id": "fghij67890"
        }
      ],
      "output": [
        "download_not_allowed",
        "download_not_allowed"
      ],
      "args": [],
      "kwargs": {},
      "notes": "Tests multiple download attempts by the same member."
    },
    {
      "name": "download_after_challenge_end",
      "input": {
        "member_id": "12345",
        "submission_id": "abcde12345",
        "challenge_status": "ended"
      },
      "output": "download_not_allowed",
      "args": [],
      "kwargs": {},
      "notes": "Tests that downloads are not allowed after the challenge has ended."
    },
    {
      "name": "valid_member_download_request",
      "input": {
        "member_id": "12345",
        "submission_id": "abcde12345"
      },
      "output": "download_not_allowed",
      "args": [],
      "kwargs": {},
      "notes": "Tests that even a valid member cannot download their submission."
    },
    {
      "name": "edge_case_empty_submission_id",
      "input": {
        "member_id": "12345",
        "submission_id": ""
      },
      "output": "submission_id_required",
      "args": [],
      "kwargs": {},
      "notes": "Tests behavior when an empty submission ID is provided."
    },
    {
      "name": "edge_case_nonexistent_member",
      "input": {
        "member_id": "00000",
        "submission_id": "abcde12345"
      },
      "output": "member_not_found",
      "args": [],
      "kwargs": {},
      "notes": "Tests behavior when a nonexistent member ID is provided."
    }
  ],
  "assumptions": "Members cannot download submissions regardless of their status.",
  "notes": "Ensure to check for proper error handling in all cases."
}
